# lib/r/s7runtime.R — S7 runtime introspection for r:s7-review --runtime.
# Sourced by lib/rcmd.py (kind="s7runtime"); returns a list serialized to JSON
# by the caller. Keep the four return keys stable:
#   dead_generics, methods_on_missing_class, methods_undeclared_dependency,
#   nonenforcing_validators.
#
# The body is the former inline r_snippet("s7runtime") success path, moved
# verbatim (Python f-string → plain R; only the path literal became the
# pkg_path argument). The caller wraps the call in tryCatch + _guard, so this
# function assumes pkgload/S7/jsonlite are present and may signal on error.

s7_runtime_report <- function(pkg_path) {
suppressMessages(pkgload::load_all(pkg_path, quiet=TRUE, helpers=FALSE, export_all=FALSE)); nm <- pkgload::pkg_name(pkg_path); ns <- asNamespace(nm); objs <- mget(ls(ns, all.names=TRUE), envir=ns, ifnotfound=list(NULL)); is_gen <- function(o) inherits(o, "S7_generic"); is_cls <- function(o) inherits(o, "S7_class"); gens <- Filter(is_gen, objs); clss <- Filter(is_cls, objs); count_methods <- function(env) { if (!is.environment(env)) return(0L); n <- 0L; for (k in ls(env, all.names=TRUE)) { v <- get(k, envir=env); n <- n + if (is.environment(v)) count_methods(v) else 1L }; n }; dead <- character(); for (gn in names(gens)) { g <- gens[[gn]]; mtab <- attr(g, "methods"); if (count_methods(mtab) == 0L) dead <- c(dead, gn) }; is_noop <- function(v) { if (!is.function(v)) return(FALSE); b <- body(v); if (is.null(b) || identical(b, quote(NULL)) || isTRUE(b) || identical(b, quote(TRUE))) return(TRUE); if (is.call(b) && identical(b[[1]], as.name("{")) && length(b) == 2L) { inner <- b[[2]]; return(is.null(inner) || identical(inner, quote(NULL)) || isTRUE(inner) || identical(inner, quote(TRUE))) }; FALSE }; lax <- character(); for (cn in names(clss)) { cl <- clss[[cn]]; val <- attr(cl, "validator"); if (is.null(val)) next; if (is_noop(val)) lax <- c(lax, cn) }; base_pkgs <- tryCatch(rownames(installed.packages(priority="base")), error=function(e) c("base","methods","stats","utils","graphics","grDevices","datasets","tools")); allow <- union(c(nm, "S7"), base_pkgs); declared <- tryCatch({ d <- read.dcf(file.path(pkgload::pkg_path(pkg_path), "DESCRIPTION")); fields <- intersect(c("Imports", "Depends", "LinkingTo"), colnames(d)); raw <- paste(d[1, fields], collapse=","); parts <- unlist(strsplit(raw, ",")); parts <- trimws(vapply(strsplit(parts, "(", fixed=TRUE), `[`, character(1), 1)); parts[nzchar(parts) & parts != "NA"] }, error=function(e) character()); declared <- union(declared, allow); collect_methods <- function(env, acc) { if (!is.environment(env)) return(acc); for (k in ls(env, all.names=TRUE)) { v <- get(k, envir=env); if (is.environment(v)) acc <- collect_methods(v, acc) else acc <- c(acc, list(v)) }; acc }; missing <- list(); undeclared <- list(); for (gn in names(gens)) { g <- gens[[gn]]; ms <- collect_methods(attr(g, "methods"), list()); for (md in ms) { sigs <- attr(md, "signature"); if (is.null(sigs)) next; for (s in sigs) { if (!inherits(s, "S7_class")) next; cnm <- attr(s, "name"); cpkg <- attr(s, "package"); if (is.null(cnm) || !nzchar(cnm) || cnm %in% c("ANY", "S7_object")) next; ext <- !is.null(cpkg) && nzchar(cpkg) && !identical(cpkg, nm); resolves <- if (ext) { tryCatch(exists(cnm, envir=asNamespace(cpkg), inherits=FALSE), error=function(e) TRUE) } else { any(vapply(clss, function(o) identical(o, s), logical(1))) }; if (!resolves) { missing <- c(missing, list(list(generic=gn, class=cnm))); next }; if (ext && !(cpkg %in% declared)) undeclared <- c(undeclared, list(list(generic=gn, class=cnm, package=cpkg))) } } }; missing <- unique(missing); undeclared <- unique(undeclared); list(dead_generics=dead, methods_on_missing_class=missing, methods_undeclared_dependency=undeclared, nonenforcing_validators=lax)
}
